let raw = $json.body ? ($json.body.text || '') : ($json.text || '');
const input = raw.replace(/<[^>]*>/g, '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '').trim().slice(0, 4000);
if (!input) return [{ json: { error: 'empty input' } }];
const seeds = {
  logic: ['because','therefore','step','plan','calculate','structure','reason','analyze'],
  emotion: ['feel','love','hate','fear','joy','pain','beautiful','soul','heart'],
  memory: ['remember','last time','before','history','previously','recall','past'],
  creativity: ['imagine','create','design','invent','dream','recipe','verse','sacred','geometry','art'],
  vigilance: ['danger','risk','careful','threat','warning','suspicious','protect']
};
const dims = Object.keys(seeds);
const lower = input.toLowerCase();
const scored = dims.map(d => ({ d, w: seeds[d].filter(k => lower.includes(k)).length + 0.1 }));
const total = scored.reduce((s, x) => s + x.w, 0);
scored.forEach(s => s.w /= total);
scored.sort((a, b) => b.w - a.w);
const angles = { logic: 0, emotion: 1.257, memory: 2.513, creativity: 3.770, vigilance: 5.027 };
let interf = 0;
for (let i = 0; i < scored.length; i++) {
  for (let j = i+1; j < scored.length; j++) {
    const diff = Math.abs(angles[scored[i].d] - angles[scored[j].d]);
    interf += Math.cos(Math.min(diff, 6.283 - diff)) * scored[i].w * scored[j].w;
  }
}
return [{ json: {
  raw_input: input,
  dim_1: scored[0].d, w_1: scored[0].w,
  dim_2: scored[1].d, w_2: scored[1].w,
  dim_3: scored[2].d, w_3: scored[2].w,
  dim_4: scored[3].d, w_4: scored[3].w,
  dim_5: scored[4].d, w_5: scored[4].w,
  interference: interf,
  gate_decision: scored.map(x => x.d)
} }];

const text = $json.choices?.[0]?.message?.content || 'no response';
const prev = $('2. Fracture + Gate').first().json;
return [{ json: { ...prev, logic_response: text } }];

const text = $json.choices?.[0]?.message?.content || 'no response';
const prev = $('3t. Logic Tag').first().json;
return [{ json: { ...prev, emotion_response: text } }];

const text = $json.choices?.[0]?.message?.content || 'no response';
const prev = $('4t. Emotion Tag').first().json;
return [{ json: { ...prev, memory_response: text } }];

const text = $json.choices?.[0]?.message?.content || 'no response';
const prev = $('5t. Memory Tag').first().json;
return [{ json: { ...prev, creativity_response: text } }];

const text = $json.choices?.[0]?.message?.content || 'no response';
const prev = $('6t. Creativity Tag').first().json;
return [{ json: { ...prev, vigilance_response: text } }];

const d = $json;
const experts = [
  { dimension: d.dim_1, weight: d.w_1, text: d.logic_response || '' },
  { dimension: d.dim_2, weight: d.w_2, text: d.emotion_response || '' },
  { dimension: d.dim_3, weight: d.w_3, text: d.memory_response || '' },
  { dimension: d.dim_4, weight: d.w_4, text: d.creativity_response || '' },
  { dimension: d.dim_5, weight: d.w_5, text: d.vigilance_response || '' }
];
const totalW = experts.reduce((s, e) => s + e.weight, 0) || 1;
const collapsed = experts
  .sort((a, b) => b.weight - a.weight)
  .map(e => '[' + e.dimension + ' w=' + (e.weight/totalW).toFixed(2) + ']: ' + e.text)
  .join('\n');
const interf = d.interference || 0;
return [{ json: {
  manifested_response: collapsed,
  expert_count: 5,
  interference: interf,
  gain: 1.0 + 0.2 * interf,
  type: interf > 0 ? 'constructive' : 'destructive',
  experts_activated: d.gate_decision || [],
  written_to_hub: true,
  hub_lobe_id: 'pineal_gate',
  timestamp: new Date().toISOString()
} }];
